ucs.kql:
// Ferocious Kitten / MarkiRAT — Telegram Desktop & Chrome shortcut hijack persistence
let TelegramFolder = @"\AppData\Roaming\Telegram Desktop\";
let ImplantNames = dynamic(["chrome_update.exe","Updater.exe","telegram_update.exe"]);
let TrustedWriters = dynamic(["telegram.exe","updater.exe","msiexec.exe","explorer.exe","googleupdate.exe","chrome.exe","setup.exe"]);
// (1) suspicious binary written into Telegram Desktop user folder
let TelegramDrops =
    DeviceFileEvents
    | where Timestamp > ago(30d)
    | where ActionType in ("FileCreated","FileModified","FileRenamed")
    | where FolderPath has TelegramFolder
    | where FileName endswith ".exe" or FileName endswith ".dll"
    | where tolower(InitiatingProcessFileName) !in (TrustedWriters);
// (2) Chrome / Telegram .lnk re-targeted by a non-installer process
let ShortcutHijacks =
    DeviceFileEvents
    | where Timestamp > ago(30d)
    | where ActionType in ("FileCreated","FileModified")
    | where FileName endswith ".lnk"
    | where tolower(FileName) has_any ("chrome", "telegram")
    | where FolderPath has_any (@"\Desktop\", @"\Start Menu\")
    | where tolower(InitiatingProcessFileName) !in (TrustedWriters);
// (3) processes named like the legit updater but launched from user-writable paths
let MasqueradedProcs =
    DeviceProcessEvents
    | where Timestamp > ago(30d)
    | where FileName in~ (ImplantNames)
    | where FolderPath has_any (@"\AppData\", @"\Users\Public\", @"\ProgramData\")
    | where InitiatingProcessFolderPath !has @"\Program Files\Google\" and InitiatingProcessFolderPath !has @"\Telegram Desktop\";
union isfuzzy=true
    (TelegramDrops    | extend Signal = "telegram_folder_write"),
    (ShortcutHijacks  | extend Signal = "shortcut_target_rewrite"),
    (MasqueradedProcs | extend Signal = "masqueraded_updater_exec"
                      | extend FolderPath = FolderPath
                      | extend InitiatingProcessFileName = InitiatingProcessFileName)
| project Timestamp, Signal, DeviceName,
          AccountName = coalesce(InitiatingProcessAccountName, AccountName),
          FileName, FolderPath, SHA256,
          Writer = InitiatingProcessFileName,
          WriterCmd = InitiatingProcessCommandLine
| order by Timestamp desc

