let TrustedWriters = dynamic(["telegram.exe","updater.exe","msiexec.exe","explorer.exe","googleupdate.exe","chrome.exe","setup.exe"]);
let TelegramDrops =
    ImFileEvent
    | where TimeGenerated > ago(30d)
    | where EventType in ("FileCreated","FileModified","FileRenamed")
    | where TargetFilePath has TelegramFolder
    | where TargetFileName endswith ".exe" or TargetFileName endswith ".dll"
    | where tolower(ActingProcessName) !in (TrustedWriters);
let ShortcutHijacks =
    ImFileEvent
    | where TimeGenerated > ago(30d)
    | where EventType in ("FileCreated","FileModified")
    | where TargetFileName endswith ".lnk"
    | where tolower(TargetFileName) has_any ("chrome", "telegram")
    | where TargetFilePath has_any (@"\Desktop\", @"\Start Menu\")
    | where tolower(ActingProcessName) !in (TrustedWriters);
let MasqueradedProcs =
    ImProcessCreate
    | where TimeGenerated > ago(30d)
    | where tolower(tostring(split(TargetProcessName, "\\")[-1])) in~ (ImplantNames)
    | where TargetProcessName has_any (@"\AppData\", @"\Users\Public\", @"\ProgramData\")
    | where ParentProcessName !has @"\Program Files\Google\" and ParentProcessName !has @"\Telegram Desktop\";
union isfuzzy=true
    (TelegramDrops    | extend Signal = "telegram_folder_write",   FileName = TargetFileName, FolderPath = TargetFilePath, Writer = ActingProcessName, WriterCmd = ActingProcessCommandLine, Host = DvcHostname, Account = ActorUsername),
    (ShortcutHijacks  | extend Signal = "shortcut_target_rewrite", FileName = TargetFileName, FolderPath = TargetFilePath, Writer = ActingProcessName, WriterCmd = ActingProcessCommandLine, Host = DvcHostname, Account = ActorUsername),
    (MasqueradedProcs | extend Signal = "masqueraded_updater_exec",FileName = TargetProcessName, FolderPath = TargetProcessName, Writer = ParentProcessName,  WriterCmd = TargetProcessCommandLine,   Host = DvcHostname, Account = ActorUsername)
| project TimeGenerated, Signal, Host, Account, FileName, FolderPath, Writer, WriterCmd
| order by TimeGenerated desc
